39	self	agent/cli.py	function	main	50	141	def main() -> None:\n    if not db.ping():\n        console.print("[red]Không kết nối được Postgres. Hãy chạy: docker compose up -d[/red]")\n        sys.exit(1)\n\n    chat_agent = Agent(session_id="cli")\n    react_agent = ReActAgent(session_id="cli-agent", confirm=_confirm)\n    mode = "chat"\n\n    router_state = "auto" if settings.router_enabled else "tắt"\n    console.print(\n        f"[bold green]Sẵn sàng[/bold green] — router [cyan]{router_state}[/cyan] "\n        f"(nhỏ={settings.llm_model_small}, lớn={settings.llm_model_large}). Gõ /help.\\n"\n    )\n\n    while True:\n        try:\n            user_input = console.input(f"[bold blue]{mode}[/bold blue] > ").strip()\n        except (EOFError, KeyboardInterrupt):\n            console.print("\\nTạm biệt!")\n            break\n\n        if not user_input:\n            continue\n        if user_input == "/exit":\n            console.print("Tạm biệt!")\n            break\n        if user_input == "/help":\n            console.print(HELP)\n            continue\n        if user_input == "/chat":\n            mode = "chat"\n            console.print("[magenta]→ chế độ chat[/magenta]")\n            continue\n        if user_input == "/agent":\n            mode = "agent"\n            console.print("[magenta]→ chế độ agent (tự dùng công cụ)[/magenta]")\n            continue\n        if user_input.startswith("/model"):\n            parts = user_input.split()\n            val = parts[1] if len(parts) > 1 else ""\n            if val == "auto":\n                chat_agent.force_tier = react_agent.force_tier = None\n                console.print("[magenta]Router: tự động[/magenta]")\n            elif val in ("small", "large"):\n                chat_agent.force_tier = react_agent.force_tier = val\n                console.print(f"[magenta]Ép model tier: {val}[/magenta]")\n            else:\n                console.print("Cách dùng: /model auto|small|large")\n            continue\n        if user_input.startswith("/scan"):\n            parts = user_input.split(maxsplit=1)\n            if len(parts) < 2:\n                console.print("Cách dùng: /scan <đường_dẫn_thư_mục>")\n                continue\n            path = parts[1].strip().strip('"')\n            console.print(f"[dim]Đang quét {path} ...[/dim]")\n            try:\n                n = codebase.scan_repo(path, repo_name=Path(path).resolve().name)\n                console.print(f"[green]Đã index {n} symbol từ '{path}'.[/green]")\n            except Exception as exc:  # noqa: BLE001\n                console.print(f"[red]Lỗi quét: {exc}[/red]")\n            continue\n        if user_input == "/recent":\n            agent_obj = chat_agent if mode == "chat" else react_agent\n            for it in agent_obj.memory.recent(20):\n                console.print(f"  [dim]({it.role})[/dim] {it.content}")\n            continue\n        if user_input == "/clear":\n            agent_obj = chat_agent if mode == "chat" else react_agent\n            n = agent_obj.memory.clear()\n            console.print(f"[yellow]Đã xoá {n} dòng bộ nhớ.[/yellow]")\n            continue\n\n        if mode == "chat":\n            first = True\n            try:\n                for piece in chat_agent.ask_stream(user_input, on_event=_on_event):\n                    if first:\n                        console.print("[bold green]Agent >[/bold green] ", end="")\n                        first = False\n                    sys.stdout.write(piece)\n                    sys.stdout.flush()\n                sys.stdout.write("\\n\\n")\n            except Exception as exc:  # noqa: BLE001\n                console.print(f"\\n[red]Lỗi: {exc}[/red]")\n        else:\n            try:\n                answer = react_agent.run(user_input, on_event=_on_event)\n                console.print(f"[bold green]Agent >[/bold green] {answer}\\n")\n            except Exception as exc:  # noqa: BLE001\n                console.print(f"[red]Lỗi: {exc}[/red]