48	self	agent/codebase.py	function	scan_repo	152	208	def scan_repo(\n    repo_path: str,\n    repo_name: str | None = None,\n    exclude_dirs: set[str] | None = None,\n    batch_size: int = 64,\n) -> int:\n    """Quét thư mục, bóc symbol, embed và lưu vào bảng code_chunks.\n\n    Trả về số symbol đã index. Ghi đè dữ liệu cũ của cùng repo_name.\n    """\n    repo = Path(repo_path).resolve()\n    repo_name = repo_name or repo.name\n    exclude = set(exclude_dirs) if exclude_dirs else set(_DEFAULT_EXCLUDES)\n\n    collected: list[tuple[str, Symbol]] = []\n    for path in sorted(repo.rglob("*")):\n        if path.is_dir() or _is_excluded(path, repo, exclude):\n            continue\n        lang = _LANG_BY_EXT.get(path.suffix.lower())\n        if not lang:\n            continue\n        try:\n            source = path.read_bytes()\n        except OSError:\n            continue\n        rel = str(path.relative_to(repo))\n        for sym in _extract_symbols(source, lang):\n            if sym.content.strip():\n                collected.append((rel, sym))\n\n    if not collected:\n        return 0\n\n    # Xoá dữ liệu cũ của repo này rồi nạp lại.\n    with db.connect() as conn:\n        conn.execute("DELETE FROM code_chunks WHERE repo = %s", (repo_name,))\n\n    inserted = 0\n    for i in range(0, len(collected), batch_size):\n        batch = collected[i : i + batch_size]\n        vectors = embed_batch([_embed_input(rel, s) for rel, s in batch])\n        with db.connect() as conn, conn.cursor() as cur:\n            for (rel, s), vec in zip(batch, vectors):\n                cur.execute(\n                    """\n                    INSERT INTO code_chunks\n                        (repo, file_path, symbol_type, symbol_name,\n                         start_line, end_line, content, embedding)\n                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s::vector)\n                    """,\n                    (\n                        repo_name, rel, s.symbol_type, s.symbol_name,\