49	self	agent/codebase.py	function	search_code	211	239	def search_code(query: str, top_k: int = 5, repo: str | None = None) -> list[CodeHit]:\n    """Tìm các đoạn code liên quan nhất tới `query` theo ngữ nghĩa."""\n    qvec = db.to_vector(embed(query))\n\n    sql = [\n        """\n        SELECT file_path, symbol_type, symbol_name, start_line, end_line, content,\n               1 - (embedding <=> %s::vector) AS similarity\n        FROM code_chunks\n        WHERE embedding IS NOT NULL\n        """\n    ]\n    params: list = [qvec]\n    if repo:\n        sql.append("AND repo = %s")\n        params.append(repo)\n    sql.append("ORDER BY embedding <=> %s::vector LIMIT %s")\n    params.extend([qvec, top_k])\n\n    with db.connect() as conn:\n        rows = conn.execute("\\n".join(sql), params).fetchall()\n\n    return [\n        CodeHit(\n            file_path=r[0], symbol_type=r[1], symbol_name=r[2],\n            start_line=r[3], end_line=r[4], content=r[5], similarity=float(r[6]),\n        )\n        for r in rows\n    ]	[0.007312493,0.05820498,-0.19215357,-0.061168607,0.071319394,-0.04366967,0.0017911835,-0.0126345195,-0.058746547,-0.048005056,-0.032657538,0.016798591,0.042985797,-0.008365916,-0.025070213,0.0031175371,-0.006999911,-0.03779385,-0.0064270734,0.019388886,0.0010664593,-0.052025106,0.04482147,-0.032593586,0.058125954,-0.003806554,-0.0046169735,0.0019836177,-0.029512359,-0.015119047,-0.009369986,0.042488117,0.008259271,-0.076372884,-0.015122717,-0.018570252,0.06252525,0.032838885,-0.024729196,0.012880663,0.019386569,0.008781655,-0.0010201784,-0.06124304,0.01360632,-0.041878276,0.06256705,-0.02817542,0.03792146,-0.08839915,0.020736398,0.015392461,0.010045864,-0.015163796,0.059836533,0.06907842,-0.01110054,0.005158052,0.008625371,-0.005672565,0.065213464,0.06369108,-0.019366309,0.030788377,0.045379166,-0.01913627,-0.023027727,0.030950513,-0.031529564,-0.007983022,0.029052584,-0.005214219,0.020259557,0.036095455,-0.053452432,-0.00089163316,-0.034070544,-0.0135