53	self	agent/core.py	class	Agent	25	69	class Agent:\n    def __init__(self, session_id: str = "default", force_tier: str | None = None) -> None:\n        self.memory = ConversationMemory(session_id)\n        self.force_tier = force_tier\n\n    def build_messages(self, user_input: str) -> list[dict]:\n        messages: list[dict] = [{"role": "system", "content": SYSTEM_PROMPT}]\n\n        similar = self.memory.retrieve_similar(user_input)\n        if similar:\n            lines = "\\n".join(f"- ({it.role}) {it.content}" for it in similar)\n            messages.append(\n                {"role": "system", "content": f"Ngữ cảnh liên quan từ hội thoại trước:\\n{lines}"}\n            )\n\n        for it in self.memory.recent(n=6):\n            role = it.role if it.role in ("user", "assistant") else "user"\n            messages.append({"role": role, "content": it.content})\n\n        messages.append({"role": "user", "content": user_input})\n        return messages\n\n    def ask(self, user_input: str, on_event: EventHook | None = None) -> str:\n        rt = router.route(user_input, force_tier=self.force_tier)\n        if on_event:\n            on_event("router", rt.spec.name, f"{rt.tier}: {rt.reason}")\n        answer = llm.chat(self.build_messages(user_input), spec=rt.spec).content\n        self._remember(user_input, answer)\n        return answer\n\n    def ask_stream(self, user_input: str, on_event: EventHook | None = None) -> Iterator[str]:\n        rt = router.route(user_input, force_tier=self.force_tier)\n        if on_event:\n            on_event("router", rt.spec.name, f"{rt.tier}: {rt.reason}")\n        messages = self.build_messages(user_input)\n        parts: list[str] = []\n        for piece in llm.chat_stream(messages, spec=rt.spec):\n            parts.append(piece)\n            yield piece\n        self._remember(user_input, "".join(parts))\n\n    def _remember(self, user_input: str, answer: str) -> None:\n        self.memory.add("user", user_input)\n        if answer.strip():\n            self.memory.add("assistant", answer)	[-0.033484425,0.012277479,-0.16109689,-0.08584089,0.093886554,-0.054697063,0.024286915,-0.033332374,0.0330747,-0.02375634,-0.025730005,0.027694086,0.007659488,-0.013083296,0.037257146,-0.017697299,-0.007998299,-0.038528312,-0.025769088,0.006909809,0.0077067954,-0.03334683,0.07232328,-0.00770597,0.087549284,0.021130618,0.041890275,-0.016077805,-0.003262224,0.0014214399,0.058944978,0.034292646,0.012284854,-0.051618677,-0.020241326,-0.02676588,0.033941567,0.030015394,-0.034732122,-0.007429604,-0.00079379644,-0.016958978,0.020804655,-0.07401375,0.030595371,-0.036925063,0.049328357,0.009215263,-0.014591147,0.010499959,0.02767227,-0.04413977,-0.028267456,-0.027097935,0.11957247,0.08112805,-0.035816938,0.015515193,0.021174228,-0.030340333,0.089264445,0.029813861,-0.055387907,0.08996801,0.039949633,-0.041590486,-0.046908185,0.06873142,-0.039539665,0.0055176243,0.046307143,-0.035187867,0.020512177,-0.03367231,-0.017589621,0.0546884,-0.04443014,0.0064797034,-0.006763855,0.059730608,0.013018876,-0.02918618,0.06469527,-0.003853136,0.04642076,-0.012909048,-0.04713432,0.0051725046,-0.011601713,0.064859994,-0.0038137,-0.015053384,0.01294097,0.0031675515,-0.059046548,0.03798676,-0.03994037,-0.058329504,0.023773337,-0.009057345,-0.031901766,-0.027530152,0.0029974058,-0.046190668,0.018712347,0.0662952,-0.025648646,0.014265582,0.0048812497,0.02955853,-0.008105985,0.03542614,-0.02537184,-0.012951479,0.024852967,-0.037782114,0.061828457,0.020489898,0.020453272,0.025075106,-0.026150662,-0.050778963,0.012277483,0.085262395,0.008647561,0.026715541,-0.02754146,0.013134736,-0.003283227,-0.037698336,-0.057774536,-0.063858844,-0.057614136,-0.061312124,0.0655463,0.07126626,-0.058599994,-0.10172688,0.037634287,-0.0018774753,-0.007976316,0.046578147,-0.019547217,-0.016844105,-0.019918786,-0.028909696,0.024285898,-0.0063973237,-0.038226526,0.029718213,0.011629795,0.07776088,-0.019666027,0.00027641328,0.045523908,0.008478648,0.02