75	self	agent/memory.py	class	ConversationMemory	29	122	class ConversationMemory:\n    """Quản lý bộ nhớ hội thoại cho 1 phiên (session)."""\n\n    def __init__(self, session_id: str = "default") -> None:\n        self.session_id = session_id\n\n    def add(self, role: str, content: str, dedup: bool = True) -> int | None:\n        """Lưu 1 lượt hội thoại kèm embedding. Trả về id, hoặc None nếu bị bỏ (trùng)."""\n        content = content.strip()\n        if not content:\n            return None\n\n        vec = embed(content)\n\n        if dedup and self._is_duplicate(vec):\n            return None\n\n        with db.connect() as conn:\n            row = conn.execute(\n                """\n                INSERT INTO conversation_memory (session_id, role, content, embedding)\n                VALUES (%s, %s, %s, %s::vector)\n                RETURNING id\n                """,\n                (self.session_id, role, content, db.to_vector(vec)),\n            ).fetchone()\n        return int(row[0]) if row else None\n\n    def retrieve_similar(\n        self,\n        query: str,\n        top_k: int | None = None,\n        min_similarity: float | None = None,\n    ) -> list[MemoryItem]:\n        """Tìm các lượt cũ liên quan nhất tới `query` (đã lọc theo ngưỡng)."""\n        top_k = top_k or settings.memory_top_k\n        min_sim = settings.memory_min_similarity if min_similarity is None else min_similarity\n\n        qvec = embed(query)\n        with db.connect() as conn:\n            rows = conn.execute(\n                """\n                SELECT id, role, content, 1 - (embedding <=> %s::vector) AS similarity\n                FROM conversation_memory\n                WHERE session_id = %s AND embedding IS NOT NULL\n                ORDER BY embedding <=> %s::vector\n                LIMIT %s\n                """,\n                (db.to_vector(qvec), self.session_id, db.to_vector(qvec), top_k),\n            ).fetchall()\n\n        items = [\n            MemoryItem(id=r[0], role=r[1], content=r[2], similarity=float(r[3]))\n            for r in rows\n        ]\n        return [it for it in items if it.similarity is not None and it.similarity >= min_sim]\n\n    def recent(self, n: int = 6) -> list[MemoryItem]:\n        """Lấy n lượt gần nhất (bộ nhớ ngắn hạn, theo thứ tự thời gian)."""\n        with db.connect() as conn:\n            rows = conn.execute(\n                """\n                SELECT id, role, content FROM conversation_memory\n                WHERE session_id = %s\n                ORDER BY id DESC\n                LIMIT %s\n                """,\n                (self.session_id, n),\n            ).fetchall()\n        rows.reverse()\n        return [MemoryItem(id=r[0], role=r[1], content=r[2]) for r in rows]\n\n    def clear(self) -> int:\n        """Xoá toàn bộ bộ nhớ của phiên. Trả về số dòng đã xoá."""\n        with db.connect() as conn:\n            cur = conn.execute(\n                "DELETE FROM conversation_memory WHERE session_id = %s",\n                (self.session_id,),\n            )\n            return cur.rowcount\n\n    def _is_duplicate(self, vec: list[float]) -> bool:\n        with db.connect() as conn:\n            row = conn.execute(\n                """\n                SELECT 1 - (embedding <=> %s::vector) AS similarity\n                FROM conversation_memory\n                WHERE session_id = %s AND embedding IS NOT NULL\n                ORDER BY embedding <=> %s::vector\n                LIMIT 1\n                """,\n                (db.to_vector(vec), self.session_id, db.to_vector(vec)),\n            ).fetchone()\n        return bool(row) and float(row[0]) >= _DEDUP_SIMILARITY	[0.008102059,0.019259695,-0.17051737,-0.07306922,0.07662635,-0.040874578,0.021063583,-0.043069076,0.0022285415,-0.0067140236,-0.06060198,0.0090595605,-0.004198242,0.02123633,-0.001136896,-0.020392878,-0.040491514,-0.06484505,-0.074656695,0.021827944,-0.020880572,0.03085404,0.01505751,-0.022099242,0.09415103,0.017345715