78	self	agent/memory.py	function	retrieve_similar	57	84	def retrieve_similar(\n        self,\n        query: str,\n        top_k: int | None = None,\n        min_similarity: float | None = None,\n    ) -> list[MemoryItem]:\n        """Tìm các lượt cũ liên quan nhất tới `query` (đã lọc theo ngưỡng)."""\n        top_k = top_k or settings.memory_top_k\n        min_sim = settings.memory_min_similarity if min_similarity is None else min_similarity\n\n        qvec = embed(query)\n        with db.connect() as conn:\n            rows = conn.execute(\n                """\n                SELECT id, role, content, 1 - (embedding <=> %s::vector) AS similarity\n                FROM conversation_memory\n                WHERE session_id = %s AND embedding IS NOT NULL\n                ORDER BY embedding <=> %s::vector\n                LIMIT %s\n                """,\n                (db.to_vector(qvec), self.session_id, db.to_vector(qvec), top_k),\n            ).fetchall()\n\n        items = [\n            MemoryItem(id=r[0], role=r[1], content=r[2], similarity=float(r[3]))\n            for r in rows\n        ]\n        return [it for it in items if it.similarity is not None and it.similarity >= min_sim]	[0.024607342,0.013808647,-0.20165786,-0.04746503,0.015621256,-0.04979708,0.007234676,-0.035681974,-0.012095141,-0.016017893,-0.050438367,0.04221792,0.021704718,-0.03654458,-0.02056975,0.0024236103,-0.015298531,-0.049556673,-0.020220226,0.042916868,-0.015056076,0.024124224,0.009645532,-0.014311575,0.046048615,-0.015919872,-0.0018748374,-0.04728339,-0.012299229,0.00880762,0.077019125,0.02690557,-0.005280327,-0.0810861,0.0026196782,-0.021309305,0.025245884,0.024911297,-0.039139647,0.03694099,-0.0025683253,0.016384985,0.0078861145,-0.03384779,0.045387976,-0.0013079862,0.048099976,-0.008016783,0.0432289,-0.06547675,0.029748833,0.010285094,-0.011059384,-0.028542181,0.084181875,0.058093414,0.018826626,0.0196713,0.073262095,0.026407247,0.07885708,0.019738175,-0.065398924,0.1035901,0.044165