87	self	agent/react.py	function	run	99	139	def run(\n        self,\n        user_input: str,\n        max_steps: int | None = None,\n        on_event: EventHook | None = None,\n    ) -> str:\n        max_steps = max_steps or settings.agent_max_steps\n\n        # Router chọn model cho cả yêu cầu này\n        rt = router.route(user_input, force_tier=self.force_tier)\n        if on_event:\n            on_event("router", rt.spec.name, f"{rt.tier}: {rt.reason}")\n        tool_schemas = tools.ollama_schemas() if rt.spec.backend == "ollama" else None\n\n        messages: list = [\n            {"role": "system", "content": SYSTEM_PROMPT},\n            {"role": "user", "content": user_input},\n        ]\n\n        final = "[Đạt số bước tối đa mà chưa có câu trả lời cuối.]"\n        for _ in range(max_steps):\n            result = llm.chat(messages, spec=rt.spec, tools=tool_schemas)\n            calls = _extract_calls(result)\n\n            if not calls:\n                final = result.content or ""\n                break\n\n            messages.append({"role": "assistant", "content": result.content or ""})\n            for name, args in calls:\n                if on_event:\n                    on_event("tool_call", name, args)\n                tool_result = tools.dispatch(name, args, confirm=self.confirm)\n                if on_event:\n                    on_event("tool_result", name, tool_result)\n                messages.append({"role": "tool", "content": str(tool_result), "tool_name": name})\n\n        self.memory.add("user", user_input)\n        if final.strip():\n            self.memory.add("assistant", final)\n        return final	[-0.021301422,0.03029813,-0.17681682,-0.02244074,0.08477022,-0.07949046,0.040534306,0.04002493,0.010585538,-0.05398454,-0.050460517,0.037341207,0.045519337,0.0050763544,0.016107842,-0.042051185,0.0377103,-0.046963003,-0.055014737,0.0015938318,0.028992003,-0.04472615,0.04725956,0.021272322,0.099770986,-0.0012637589,0.037288573,0.0003929847,-0.