91	self	agent/router.py	function	classify	44	67	def classify(task: str) -> tuple[str, str]:\n    """Phân loại độ khó -> (tier, lý do)."""\n    t = task.lower()\n    score = 0\n    reasons: list[str] = []\n\n    hits = sorted({kw for kw in _LARGE_KEYWORDS if kw in t})\n    if hits:\n        score += 2\n        reasons.append("từ khóa phức tạp: " + ", ".join(hits[:3]))\n\n    if len(task) >= 400:\n        score += 1\n        reasons.append("yêu cầu dài")\n\n    # Nhiều yêu cầu con: đếm dòng + mục đánh số\n    n_reqs = task.count("\\n") + len(re.findall(r"\\b\\d+[.)]", task))\n    if n_reqs >= 3:\n        score += 1\n        reasons.append("nhiều yêu cầu con")\n\n    tier = "large" if score >= 2 else "small"\n    reason = "; ".join(reasons) if reasons else "đơn giản"\n    return tier, reason	[-0.0156034045,0.052350298,-0.16297837,-0.0664083,0.07312711,-0.07231313,0.0153461965,0.0061983773,-0.028971916,0.004540334,-0.018896515,0.037752613,0.050620083,-0.025645623,0.01653934,-0.038809933,0.0120104775,-0.03699699,-0.00866983,0.0017546023,-0.0076293224,0.03484344,0.05264682,-0.004550584,0.05422223,-0.0041587385,0.00028291406,-0.023871807,-0.013766102,0.038348578,0.010829698,0.035274852,-0.014083526,-0.075188875,-0.021163935,-0.011586927,0.064081594,0.018207967,-0.026046306,0.023606284,-0.011250105,0.0109204035,0.014339345,-0.060743045,0.030394962,-0.074273445,0.027742516,0.017840492,0.055553574,-0.03454392,0.02547675,-0.0007875116,0.0076325033,-0.01794827,0.0807698,0.056998733,-0.016319796,0.032592207,0.038974583,0.004162138,0.039969515,0.057199743,-0.08818345,0.057340693,0.07882173,-0.022561079,-0.011445292,0.04696966,-0.018310932,-0.00158205,-0.0048301076,-0.06323491,0.032031015,0.010447678,-0.0146836275,-0.0025257263,-0.030203827,0.007861664,0.012762744,0.07133878,0.028911836,-0.026826998,0.053877104,0.048204552,-0.016284559,-0.03297598,-0.04142587,0.008175214,0.0036255936,0.08734528,-0.03346754,-0.017585516,0.038706988,0.028053997,-0.04729431,0.078402944,-0.011768911,-