94	self	agent/tools.py	function	_read_path	27	35	def _read_path(rel: str) -> Path:\n    """Giới hạn đường dẫn ĐỌC trong project_root, chặn file bí mật."""\n    root = Path(settings.project_root).resolve()\n    p = (root / rel).resolve()\n    if not (p == root or root in p.parents):\n        raise ValueError(f"Đường dẫn ngoài phạm vi cho phép: {rel}")\n    if p.name in _SECRET_NAMES or p.suffix in _SECRET_SUFFIXES:\n        raise ValueError(f"Không được đọc file nhạy cảm: {p.name}")\n    return p	[0.024368016,0.015605257,-0.16604479,-0.019724315,0.06270036,-0.08562046,-0.031159647,-0.0039932337,-0.044912722,0.010252312,-0.00908776,0.009881692,0.04208661,-0.044456396,0.029660262,0.013892563,0.020961331,-0.033402253,0.025331123,-0.014301876,0.027274601,-0.0397065,0.039381072,0.013873763,0.10607393,-0.0016759284,0.040599853,-0.0035298143,-0.07862048,-0.0040902593,0.02561687,0.013567033,0.00082185544,-0.03517518,-0.05185248,-0.048899755,0.04219002,0.02840345,-0.028600644,0.023814727,0.009506493,-0.002890703,0.006574309,-0.0495594,0.014761606,-0.05230631,-0.0039091483,-0.008222726,0.056148537,-0.051861767,0.032235302,-0.031062627,0.0026753715,-0.007031664,0.11331166,0.060376164,-0.0039338456,-0.009307274,-0.015211247,-0.012752008,0.08954286,0.05970609,-0.03672325,0.08903639,0.013651678,-0.005969661,-0.019337205,0.016502865,0.00011445084,-0.01724974,0.0421243,-0.015647447,0.020636626,-0.032538153,-0.021764293,-0.018809613,-0.05152777,-0.04150291,-0.031417254,0.05197957,0.018931052,-0.025597736,0.03519459,0.03408361,-0.002834082,0.0036653338,-0.013299885,0.03739339,-0.008464079,0.049693372,-0.022680629,-0.05738775,0.020807033,-0.0017714377,-0.061700173,0.03276651,-0.03880972,0.013213473,-0.015616756,-0.012405187,-0.02415235,-0.024804287,0.0021803405,-0.0010497102,0.009240522,0.047866877,0.021582464,0.018336486,0.00077688845,0.024284363,-0.015155033,0.015825734,0.0031849633,-0.021470847,0.04710329,-0.04365082,0.07922755,-0.030194568,-0.007168245,0.033804048,-0.03129792,-0.02