100	self	agent/tools.py	function	edit_file	90	102	def edit_file(path: str, old_str: str, new_str: str) -> str:\n    """Sửa có mục tiêu: thay CHÍNH XÁC một đoạn text duy nhất trong file."""\n    p = _write_path(path)\n    if not p.is_file():\n        return f"[Lỗi] Không tìm thấy file để sửa: {path}"\n    text = p.read_text(encoding="utf-8", errors="replace")\n    count = text.count(old_str)\n    if count == 0:\n        return f"[Lỗi] Không thấy đoạn cần thay trong {path}. Hãy read_file trước để lấy đúng nội dung."\n    if count > 1:\n        return f"[Lỗi] Đoạn cần thay xuất hiện {count} lần; hãy thêm ngữ cảnh để nó là DUY NHẤT."\n    p.write_text(text.replace(old_str, new_str, 1), encoding="utf-8")\n    return f"[OK] Đã sửa {path} (thay 1 đoạn: {len(old_str)} -> {len(new_str)} ký tự)."	[0.002479166,-0.03183569,-0.15436944,-0.038564768,0.03343917,-0.07176625,-0.028966866,0.044237465,-0.054753736,0.008161049,-0.009218859,-0.010243565,0.06169355,-0.022730565,0.04430085,0.017468173,0.032843236,-0.037935574,-0.013930058,0.03461616,0.019615341,-0.04510204,0.047827777,-0.018017257,0.09636307,-0.033866275,0.032505758,0.032730974,-0.07395544,0.034651674,0.08579644,0.028991656,-0.014793726,-0.021580104,-0.03571322,-0.04210789,0.09124801,0.020805359,-0.018041613,0.0044996026,0.029071998,0.012879366,0.008248189,-0.06268945,0.031328466,-0.084446914,0.018586583,-0.01205056,0.047038548,-0.047909196,0.014408023,-0.017847726,-0.015854675,0.0153448675,0.10676607,0.07559945,0.016071973,-0.02703532,-0.009346753,-0.032900885,0.04128086,0.030880785,-0.04965615,0.06711457,0.0034600492,-0.02570411,-0.0017838546,0.005967967,-0.009841567,-0.031502366,0.047145758,0.014754666,0.020739462,0.012310161,-0.021688428,-0.02234737,-0.06350831,-0.030219741,-0.026287777,0.050694328,0.0036849037,-0.022562027,0.051373597,0.032633007,0.00033809108,-0.037788495,0.0019964825,0.033959497,-0.0069913976,0.059958696,-0.049959503,-0.03443278,0.015825044,-0.0059753344,-0.04851923,0.010661635,-0.00097388605,0.023