104	self	agent/tools.py	function	dispatch	228	242	def dispatch(name: str, args: dict, confirm: Callable[[str, dict], bool] | None = None) -> str:\n    """Thực thi 1 tool theo tên. Tool nguy hiểm cần confirm() trả True mới chạy."""\n    tool = _BY_NAME.get(name)\n    if tool is None:\n        return f"[Lỗi] Không có tool tên '{name}'."\n    if tool.dangerous:\n        allowed = confirm(name, args) if confirm else False\n        if not allowed:\n            return f"[Từ chối] Người dùng không cho phép chạy '{name}'."\n    try:\n        return tool.func(**args)\n    except TypeError as exc:\n        return f"[Lỗi tham số cho {name}] {exc}"\n    except Exception as exc:  # noqa: BLE001\n        return f"[Lỗi khi chạy {name}] {exc}"	[0.0012087157,0.010573315,-0.16514204,-0.05544894,0.101286605,-0.097496055,-0.025050433,-0.010856836,-0.043218195,-0.03497546,-0.044424284,0.0061074663,0.07661989,-0.029359076,0.014961026,-0.030465255,0.024972524,-0.059096053,-0.015909351,0.020324383,0.0548557,-0.033845384,0.038852155,-0.022880102,0.12520677,-0.050449196,0.03452189,0.019186286,-0.026191708,-0.010886564,-0.0018536536,0.060557306,0.024221864,-0.06054002,-0.04410734,-0.021236796,0.04076782,0.011810548,-0.02380628,-0.020316534,-0.0010418494,0.018070064,0.020115308,-0.030896943,0.020771993,-0.05150832,0.035369996,0.04246939,0.038479142,-0.043253385,0.05051174,-0.05672567,-0.01941185,-0.020280208,0.103580564,0.06379733,0.032758705,0.0486788,0.0036904279,-0.036478978,0.03843258,0.086910374,-0.026951063,0.053911153,0.057313774,-0.012299484,-0.02083248,0.024538653,0.05032663,0.0019742367,0.0063066776,-0.025762798,0.063455656,-0.012446041,-0.009394256,0.036285162,-0.03496061,-0.024660045,-0.06582214,0.02964346,0.0026288454,-0.012726143,0.012578234,-0.01115144,-0.009500667,0.00063030375,-0.024526667,0.031810135,0.022385515,0.06743246,-0.02174447,-0.040878557,0.003376352,0.021570655,-0.032251693,0.052100874,-0.014664932,-0.033220623,-0.0006404608,-0.04437954,0.008670895,0.0007890097,-0.0